const medicines = $input.all();

if (medicines.length === 0) {
  return [];
}

const today = new Date().toLocaleString();

let lowStock = [];
let expiring = [];

for (const item of medicines) {

    if(item.json.status === "LOW_STOCK"){
        lowStock.push(item.json);
    }

    if(item.json.status === "EXPIRING_SOON"){
        expiring.push(item.json);
    }

}

let html = `
<h2>🏥 Pharmacy Daily Report</h2>

<p><b>Date:</b> ${today}</p>
`;

if(lowStock.length){

html += `
<h3 style="color:red;">Low Stock Medicines</h3>

<table border="1" cellpadding="6">

<tr>

<th>Name</th>

<th>Current</th>

<th>Minimum</th>

<th>Supplier</th>

</tr>
`;

for(const medicine of lowStock){

html += `
<tr>

<td>${medicine.name}</td>

<td>${medicine.quantity}</td>

<td>${medicine.minimum_quantity}</td>

<td>${medicine.supplier}</td>

</tr>
`;

}

html += "</table>";

}

if(expiring.length){

html += "<br><h3 style='color:orange;'>Expiring Soon</h3>";

html += `
<table border="1" cellpadding="6">

<tr>

<th>Name</th>

<th>Expiry Date</th>

</tr>
`;

for(const medicine of expiring){

html += `
<tr>

<td>${medicine.name}</td>

<td>${medicine.expiry_date}</td>

</tr>
`;

}

html += "</table>";

}

return [

{

json:{

message:html,

count:medicines.length

}

}

];
